spec.expr:
100 * max(
  process_cpu_usage{
    job="limitedgoods"
  }
)

100 *
(
  sum(
    jvm_memory_used_bytes{
      job="limitedgoods",
      area="heap"
    }
  )
  /
  sum(
    jvm_memory_max_bytes{
      job="limitedgoods",
      area="heap"
    } > 0
  )
)

1000 *
(
  (
    sum(
      rate(
        jvm_gc_pause_seconds_sum{
          job="limitedgoods"
        }[$__rate_interval]
      )
    )
    or vector(0)
  )
  /
  clamp_min(
    (
      sum(
        rate(
          jvm_gc_pause_seconds_count{
            job="limitedgoods"
          }[$__rate_interval]
        )
      )
      or vector(0)
    ),
    0.000001
  )
)

max(
  jvm_threads_live_threads{
    job="limitedgoods"
  }
) or vector(0)

sum by (state) (
  jvm_threads_states_threads{
    job="limitedgoods"
  }
)

(
  100 *
  max(
    hikaricp_connections_active{
      job="limitedgoods"
    }
    /
    clamp_min(
      hikaricp_connections_max{
        job="limitedgoods"
      },
      1
    )
  )
) or vector(0)

max(
  up{
    job="limitedgoods"
  }
) or vector(0)

max(
  limitedgoods_dependency_up{
    dependency="redis"
  }
) or vector(-1)

round(
  sum(
    increase(
      limitedgoods_payment_revenue_total[1h]
    )
  )
) or vector(0)

round(
  sum(
    increase(
      limitedgoods_payment_revenue_total[$__rate_interval]
    )
  )
) or vector(0)

sum(
  rate(
    http_server_requests_seconds_count{
      job="limitedgoods",
      uri!~"/actuator.*"
    }[$__rate_interval]
  )
)

round(
  sum(
    increase(
      limitedgoods_payment_total{
        result="success"
      }[1h]
    )
  )
) or vector(0)

100 *
(
  (
    sum(
      rate(
        limitedgoods_payment_total{
          result="failure"
        }[$__rate_interval]
      )
    )
    or vector(0)
  )
  /
  clamp_min(
    (
      sum(
        rate(
          limitedgoods_payment_total{
            result="success"
          }[$__rate_interval]
        )
      )
      or vector(0)
    )
    +
    (
      sum(
        rate(
          limitedgoods_payment_total{
            result="failure"
          }[$__rate_interval]
        )
      )
      or vector(0)
    ),
    0.000001
  )
)

100 *
(
  (
    sum(
      rate(
        http_server_requests_seconds_count{
          job="limitedgoods",
          uri!~"/actuator.*",
          status=~"5.."
        }[5m]
      )
    )
    or vector(0)
  )
  /
  clamp_min(
    (
      sum(
        rate(
          http_server_requests_seconds_count{
            job="limitedgoods",
            uri!~"/actuator.*"
          }[5m]
        )
      )
      or vector(0)
    ),
    0.000001
  )
)

histogram_quantile(
  0.95,
  sum by (le) (
    rate(
      http_server_requests_seconds_bucket{
        job="limitedgoods",
        uri!~"/actuator.*"
      }[$__rate_interval]
    )
  )
)

100 *
(
  sum(
    rate(
      http_server_requests_seconds_count{
        job="limitedgoods",
        uri!~"/actuator.*",
        status!~"5.."
      }[$__rate_interval]
    )
  )
  /
  sum(
    rate(
      http_server_requests_seconds_count{
        job="limitedgoods",
        uri!~"/actuator.*"
      }[$__rate_interval]
    )
  )
)

100 *
(
  sum(
    increase(
      http_server_requests_seconds_count{
        job="limitedgoods",
        uri!~"/actuator.*",
        status!~"5.."
      }[15d]
    )
  )
  /
  sum(
    increase(
      http_server_requests_seconds_count{
        job="limitedgoods",
        uri!~"/actuator.*"
      }[15d]
    )
  )
)

round(
  sum(
    increase(
      limitedgoods_order_create_total{
        result="failure",
        reason=~"PRODUCT_002|QUEUE_001"
      }[1h]
    )
  )
) or vector(0)

round(
  sum(
    increase(
      limitedgoods_order_create_total{
        result="failure",
        reason=~"PRODUCT_002|QUEUE_001"
      }[$__rate_interval]
    )
  )
) or vector(0)

round(
  sum by (reason) (
    increase(
      limitedgoods_order_expired_total[$__rate_interval]
    )
  )
)
